3	import java.time.Duration;
4	import java.time.Instant;
5	import java.util.ArrayList;
6	import java.util.List;
7	import java.util.Map;
8	import java.util.concurrent.ConcurrentHashMap;
9	import java.util.concurrent.atomic.AtomicInteger;
10	
11	import com.interview.lld.moviebooking.gateway.Clock;
12	import com.interview.lld.moviebooking.model.InvalidBookingException;
13	import com.interview.lld.moviebooking.model.SeatHold;
14	import com.interview.lld.moviebooking.model.SeatStatus;
15	import com.interview.lld.moviebooking.model.SeatsUnavailableException;
16	import com.interview.lld.moviebooking.model.ShowSeat;
17	import com.interview.lld.moviebooking.model.Showtime;
18	import com.interview.lld.moviebooking.model.Ticket;
19	import com.interview.lld.moviebooking.model.UnknownShowtimeException;
20	
21	// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
22	// The brain. It coordinates every operation: hold seats, confirm payment, cancel,
23	// and sweep expired holds. It owns the registry of showtimes and the registry of
24	// live holds. It does NOT change seat status itself — it asks each ShowSeat to
25	// hold/confirm/release, so the state-machine rules live in one place.
26	//
27	// This is the CLEAN, single-threaded core. There are ZERO locks in this file.
28	// The thread-safe version (§9, ThreadSafeBookingService) is a subclass that
29	// overrides ONE pair of hook methods. That keeps the OO design the star here.
30	//
31	// 🎙️ "BookingService is the orchestrator. It holds the showtimes and the live
32	//      holds, and it drives the seat state machine. There is no lock code in this
33	//      file at all — the thread-safe version is a subclass that overrides two
34	//      tiny hooks."
35	public class BookingService {
36	
37	    // 10-minute hold window. A held seat the user does not pay for is released
38	    // after this. Configurable per-instance so tests can shrink it if needed.
39	    public static final Duration HOLD_DURATION = Duration.ofMinutes(10);
40	
41	    private final Clock clock;
42	    private final Duration holdDuration;
43	
44	    // showtime id -> Showtime. Showtimes are registered once at setup.
45	    private final Map<String, Showtime> showtimes = new ConcurrentHashMap<>();
46	
47	    // hold id -> SeatHold. The orchestrator owns the truth about every live hold,
48	    // so the sweeper can enumerate them and confirm() can look one up in O(1).
49	    private final Map<String, SeatHold> holds = new ConcurrentHashMap<>();
50	
51	    // WHY: counter-based ids (hold-1, tkt-2) make test assertions readable. In
52	    //      production I would switch to UUIDs. AtomicInteger so id minting is safe
53	    //      even before any lock is held.
54	    private final AtomicInteger holdCounter = new AtomicInteger(0);
55	    private final AtomicInteger ticketCounter = new AtomicInteger(0);
56	
57	    public BookingService(Clock clock) {
58	        this(clock, HOLD_DURATION);
59	    }
60	
61	    public BookingService(Clock clock, Duration holdDuration) {
62	        this.clock = clock;
63	        this.holdDuration = holdDuration;
64	    }
65	
66	    // WHY: register a screening up front. Setup-time, not part of the booking
67	    //      hot path, so no lock needed.
68	    public void addShowtime(Showtime showtime) {
69	        showtimes.put(showtime.getShowtimeId(), showtime);
70	    }
71	
72	    // ── Public op 1: holdSeats ───────────────────────────────────────────────
73	    // WHY: this is the two-phase commit. Phase 1: CHECK every requested seat is
74	    //      AVAILABLE. Phase 2: only if ALL pass, HOLD every seat. If even one is
75	    //      taken, we touch nothing and throw with the conflicting labels. That is
76	    //      the all-or-nothing rule the problem cares about.
77	    public SeatHold holdSeats(String showtimeId, List<String> seatLabels) {
78	        Showtime showtime = requireShowtime(showtimeId);
79	        validateSeatRequest(showtime, seatLabels);
80	
81	        // gateLock() does NOTHING in this clean class. The thread-safe subclass
82	        // overrides it to take the per-showtime lock around the whole check+hold.
83	        gateLock(showtimeId);
84	        try {
85	            List<ShowSeat> targets = resolveSeats(showtime, seatLabels);
86	
87	            // PHASE 1 — CHECK all. Collect every seat that is not free.
88	            List<String> conflicts = new ArrayList<>();
89	            for (ShowSeat seat : targets) {
90	
91	                if (!seat.isAvailable()) {
92	                    conflicts.add(seat.getSeatLabel());
93	                }
94	            }
95	            if (!conflicts.isEmpty()) {
96	                // WHY: back out without holding anything. No seat was touched, so
97	                //      there is nothing to roll back — that is the whole point of
98	                //      checking all BEFORE holding any.
99	                throw new SeatsUnavailableException(conflicts);
100	            }
101	
102	            // PHASE 2 — HOLD all. Every seat passed, so this cannot fail midway.
103	            String holdId = "hold-" + holdCounter.incrementAndGet();
104	            Instant expiresAt = clock.now().plus(holdDuration);
105	            for (ShowSeat seat : targets) {
106	                seat.hold(holdId, expiresAt);
107	            }
108	            SeatHold hold = new SeatHold(holdId, showtimeId, seatLabels, expiresAt);
109	            holds.put(holdId, hold);
110	            return hold;
111	        } finally {
112	            gateUnlock(showtimeId);
113	        }
114	    }
115	
116	    // ── Public op 2: confirmBooking ──────────────────────────────────────────
117	    // WHY: turn a live hold into a paid ticket. Guard the expiry FIRST so a hold
118	    //      that timed out (or was swept) can never be confirmed. Then flip every
119	    //      held seat to BOOKED and issue the immutable ticket.
120	    public Ticket confirmBooking(String holdId) {
121	        // WHY: resolve which showtime this hold belongs to ONCE, before locking,
122	        //      so we always lock and unlock the SAME showtime even though the hold
123	        //      gets removed from the map inside the locked region.
124	        String showtimeId = requireShowtimeIdForHold(holdId);
125	        Showtime showtime = showtimes.get(showtimeId);
126	        SeatHold hold;
127	
128	        gateLock(showtimeId);
129	        try {
130	            hold = holds.get(holdId);
131	            if (hold == null) {
132	                throw new InvalidBookingException("Unknown or already-used hold: " + holdId);
133	            }
134	            // WHY: if the hold already expired, release its seats now and reject.
135	            //      No window where a stale hold still books a seat.
136	            if (hold.isExpired(clock.now())) {
137	                releaseHold(hold);
138	                holds.remove(holdId);
139	                throw new InvalidBookingException("Hold expired: " + holdId);
140	            }
141	            for (String label : hold.seatLabels()) {
142	                showtime.getSeat(label).confirm(holdId);
143	            }
144	            holds.remove(holdId);
145	        } finally {
146	            gateUnlock(showtimeId);
147	        }
148	
149	        String ticketId = "tkt-" + ticketCounter.incrementAndGet();
150	        return new Ticket(ticketId, hold.showtimeId(), showtime.getMovieTitle(),
151	                hold.seatLabels(), clock.now());
152	    }
153	
154	    // ── Public op 3: cancelHold ──────────────────────────────────────────────
155	    // WHY: a user backed out before paying. Release the seats and drop the hold.
156	    //      Safe to call on an unknown/already-gone hold — it just does nothing.
157	    public void cancelHold(String holdId) {
158	        SeatHold known = holds.get(holdId);
159	        if (known == null) {
160	            return;   // unknown / already gone — nothing to do, no lock needed
161	        }
162	        String showtimeId = known.showtimeId();
163	
164	        gateLock(showtimeId);
165	        try {
166	            SeatHold hold = holds.remove(holdId);
167	            if (hold != null) {
168	                releaseHold(hold);
169	            }
170	        } finally {
171	            gateUnlock(showtimeId);
172	        }
173	    }
174	
175	    // ── Public op 4: sweepExpiredHolds ───────────────────────────────────────
176	    // WHY: the background cleanup. A timer thread calls this every minute. It
177	    //      finds holds older than 10 minutes and releases their seats so the
178	    //      seats go back on sale. Idempotent — each pass is independent, and
179	    //      releasing an already-freed seat is a no-op.
180	    // 🎙️ "This runs in the background. It scans live holds, and any that passed
181	    //      their 10-minute mark get released. Running it twice does no harm."
182	    public int sweepExpiredHolds() {
183	        Instant now = clock.now();
184	        int released = 0;
185	        // Snapshot the ids so we are not iterating the map while removing from it.
186	        List<String> holdIds = new ArrayList<>(holds.keySet());
187	        for (String holdId : holdIds) {
188	            SeatHold known = holds.get(holdId);
189	            if (known == null) {
190	                continue;   // already removed by a confirm/cancel between snapshot and now
191	            }
192	            String showtimeId = known.showtimeId();
193	
194	            gateLock(showtimeId);
195	            try {
196	                SeatHold hold = holds.get(holdId);
197	                if (hold != null && hold.isExpired(now)) {
198	                    releaseHold(hold);
199	                    holds.remove(holdId);
200	                    released++;
201	                }
202	            } finally {
203	                gateUnlock(showtimeId);
204	            }
205	        }
206	        return released;
207	    }
208	
209	    // ── Read helper used by demos / tests ────────────────────────────────────
210	    public long countByStatus(String showtimeId, SeatStatus status) {
211	        Showtime showtime = requireShowtime(showtimeId);
212	        return showtime.allSeats().stream().filter(s -> s.getStatus() == status).count();
213	    }
214	
215	    public int liveHoldCount() {
216	        return holds.size();
217	    }
218	
219	    // ── Private helpers ──────────────────────────────────────────────────────
220	
221	    private Showtime requireShowtime(String showtimeId) {
222	        Showtime showtime = showtimes.get(showtimeId);
223	        if (showtime == null) {
224	            throw new UnknownShowtimeException(showtimeId);
225	        }
226	        return showtime;
227	    }
228	
229	    // WHY: confirm needs to know which showtime to lock. If the hold id is bogus
230	    //      we throw the typed error here, before any lock is taken.
231	    private String requireShowtimeIdForHold(String holdId) {
232	        SeatHold hold = holds.get(holdId);
233	        if (hold == null) {
234	            throw new InvalidBookingException("Unknown or already-used hold: " + holdId);
235	        }
236	        return hold.showtimeId();
237	    }
238	
239	    // WHY: validate the request shape BEFORE mutating anything — empty list and
240	    //      unknown seat labels are caller mistakes, rejected with a clear error.
241	    private void validateSeatRequest(Showtime showtime, List<String> seatLabels) {
242	        if (seatLabels == null || seatLabels.isEmpty()) {
243	            throw new InvalidBookingException("Must request at least one seat");
244	        }
245	        for (String label : seatLabels) {
246	            if (showtime.getSeat(label) == null) {
247	                throw new InvalidBookingException(
248	                    "Unknown seat " + label + " for showtime " + showtime.getShowtimeId());
249	            }
250	        }
251	    }
252	
253	    private List<ShowSeat> resolveSeats(Showtime showtime, List<String> seatLabels) {
254	        List<ShowSeat> seats = new ArrayList<>(seatLabels.size());
255	        for (String label : seatLabels) {
256	            seats.add(showtime.getSeat(label));
257	        }
258	        return seats;
259	    }
260	
261	    // WHY: release every seat a hold covers. Used by cancel, the expiry guard in
262	    //      confirm, and the sweeper — one place, so the rule is canonical.
263	    private void releaseHold(SeatHold hold) {
264	        Showtime showtime = showtimes.get(hold.showtimeId());
265	        if (showtime == null) {
266	            return;
267	        }
268	        for (String label : hold.seatLabels()) {
269	            ShowSeat seat = showtime.getSeat(label);
270	            if (seat != null) {
271	                seat.release();
272	            }
273	        }
274	    }
275	
276	    // ── Template-method hooks (no-ops here; overridden in §9) ─────────────────
277	    // WHY: these four methods do NOTHING in this clean class. The thread-safe
278	    //      subclass overrides them to take/release a per-showtime lock. This file
279	    //      has zero lock imports — the concurrency story is entirely in the
280	    //      subclass, so the diff between "clean" and "thread-safe" is tiny.
281	    // 🎙️ "These hooks are empty here. The thread-safe subclass replaces them with
282	    //      a real per-showtime lock. My core has no lock code at all."
283	    protected void gateLock(String showtimeId) { }
284	    protected void gateUnlock(String showtimeId) { }
285	}
