32	// JUnit 5 suite. Every public method has a happy-path test, every typed exception
33	// has its own test, plus the boundary, idempotency, expiry, and concurrency tests.
34	class BookingServiceTest {
35	
36	    private static final Instant START = Instant.parse("2026-06-21T18:00:00Z");
37	
38	    private MutableClock clock;
39	    private BookingService svc;
40	
41	    @BeforeEach
42	    void setUp() {
43	        clock = new MutableClock(START);
44	        svc = new BookingService(clock);
45	        svc.addShowtime(new Showtime("show-1", "Dune Part Two",
46	                List.of("A1", "A2", "A3", "A4", "A5")));
47	    }
48	
49	    // ── holdSeats + confirmBooking happy path ────────────────────────────────
50	    @Test
51	    void holdThenConfirmBooksAllSeats() {
52	        SeatHold hold = svc.holdSeats("show-1", List.of("A1", "A2"));
53	        assertEquals(2, svc.countByStatus("show-1", SeatStatus.HELD));
54	
55	        Ticket ticket = svc.confirmBooking(hold.holdId());
56	        assertEquals(List.of("A1", "A2"), ticket.seatLabels());
57	        assertEquals("Dune Part Two", ticket.movieTitle());
58	        assertEquals(2, svc.countByStatus("show-1", SeatStatus.BOOKED));
59	        assertEquals(0, svc.liveHoldCount());
60	    }
61	
62	    // ── all-or-nothing: a partial conflict rejects the WHOLE request ─────────
63	    @Test
64	    void partialConflictRejectsEntireRequestAndTouchesNothing() {
65	        svc.holdSeats("show-1", List.of("A2"));   // A2 now HELD
66	
67	        SeatsUnavailableException ex = assertThrows(SeatsUnavailableException.class,
68	                () -> svc.holdSeats("show-1", List.of("A1", "A2", "A3")));
69	        assertEquals(List.of("A2"), ex.getConflictingSeats());
70	
71	        // A1 and A3 must remain AVAILABLE — the request backed out cleanly.
72	        assertEquals(4, svc.countByStatus("show-1", SeatStatus.AVAILABLE));
73	        assertEquals(1, svc.countByStatus("show-1", SeatStatus.HELD));
74	    }
75	
76	    // ── typed exception: unknown showtime ────────────────────────────────────
77	    @Test
78	    void unknownShowtimeRejected() {
79	        assertThrows(UnknownShowtimeException.class,
80	                () -> svc.holdSeats("ghost", List.of("A1")));
81	    }
82	
83	    // ── typed exception: empty request ───────────────────────────────────────
84	    @Test
85	    void emptySeatListRejected() {
86	        assertThrows(InvalidBookingException.class,
87	                () -> svc.holdSeats("show-1", List.of()));
88	    }
89	
90	    // ── typed exception: unknown seat label ──────────────────────────────────
91	    @Test
92	    void unknownSeatLabelRejected() {
93	        assertThrows(InvalidBookingException.class,
94	                () -> svc.holdSeats("show-1", List.of("Z9")));
95	    }
96	
97	    // ── typed exception: confirm an unknown hold ─────────────────────────────
98	    @Test
99	    void confirmUnknownHoldRejected() {
100	        assertThrows(InvalidBookingException.class,
101	                () -> svc.confirmBooking("hold-999"));
102	    }
103	
104	    // ── expiry: an unpaid hold is released after 10 minutes ──────────────────
105	    @Test
106	    void unpaidHoldExpiresAndSeatsReturnToAvailable() {
107	        SeatHold hold = svc.holdSeats("show-1", List.of("A1", "A2"));
108	        assertEquals(2, svc.countByStatus("show-1", SeatStatus.HELD));
109	
110	        clock.advance(Duration.ofMinutes(11));     // jump past the 10-min window
111	        int released = svc.sweepExpiredHolds();
112	        assertEquals(1, released);
113	        assertEquals(5, svc.countByStatus("show-1", SeatStatus.AVAILABLE));
114	        assertEquals(0, svc.liveHoldCount());
115	
116	        // confirming the now-expired hold must fail.
117	        assertThrows(InvalidBookingException.class, () -> svc.confirmBooking(hold.holdId()));
118	    }
119	
120	    // ── expiry guard: confirm just past the window fails even before a sweep ─
121	    @Test
122	    void confirmAfterExpiryWindowFailsWithoutSweep() {
123	        SeatHold hold = svc.holdSeats("show-1", List.of("A1"));
124	        clock.advance(Duration.ofMinutes(10));     // exactly at the boundary => expired
125	        assertThrows(InvalidBookingException.class, () -> svc.confirmBooking(hold.holdId()));
126	        // the confirm path itself reclaimed the seat
127	        assertEquals(5, svc.countByStatus("show-1", SeatStatus.AVAILABLE));
128	    }
129	
130	    // ── not-yet-expired holds survive a sweep ────────────────────────────────
131	    @Test
132	    void sweepLeavesFreshHoldsAlone() {
133	        svc.holdSeats("show-1", List.of("A1"));
134	        clock.advance(Duration.ofMinutes(9));      // still inside the window
135	        assertEquals(0, svc.sweepExpiredHolds());
136	        assertEquals(1, svc.countByStatus("show-1", SeatStatus.HELD));
137	    }
138	
139	    // ── cancelHold frees the seats; idempotent on a stale id ─────────────────
140	    @Test
141	    void cancelHoldFreesSeatsAndIsIdempotent() {
142	        SeatHold hold = svc.holdSeats("show-1", List.of("A1", "A2"));
143	        svc.cancelHold(hold.holdId());
144	        assertEquals(5, svc.countByStatus("show-1", SeatStatus.AVAILABLE));
145	
146	        // second cancel of the same id is a safe no-op.
147	        svc.cancelHold(hold.holdId());
148	        svc.cancelHold("never-existed");
149	        assertEquals(5, svc.countByStatus("show-1", SeatStatus.AVAILABLE));
150	    }
151	
152	    // ── a booked seat cannot be held again ───────────────────────────────────
153	    @Test
154	    void bookedSeatCannotBeReheld() {
155	        SeatHold hold = svc.holdSeats("show-1", List.of("A1"));
156	        svc.confirmBooking(hold.holdId());
157	        assertThrows(SeatsUnavailableException.class,
158	                () -> svc.holdSeats("show-1", List.of("A1")));
159	    }
160	
161	    // ── CONCURRENCY: many threads, overlapping seat sets, NO double-booking ──
162	    @Test
163	    void concurrentOverlappingHoldsNeverDoubleBook() throws Exception {
164	        int threads = 50;
165	        MutableClock c = new MutableClock(START);
166	        ThreadSafeBookingService tsvc = new ThreadSafeBookingService(c);
167	        tsvc.addShowtime(new Showtime("show-x", "Interstellar",
168	                List.of("S1", "S2", "S3", "S4")));
169	
170	        // Every thread wants the SAME overlapping pair {S1, S2}. Only ONE can win.
171	        CyclicBarrier gate = new CyclicBarrier(threads);
172	        AtomicInteger wins = new AtomicInteger();
173	        AtomicInteger conflicts = new AtomicInteger();
174	        Set<String> winningHoldIds = ConcurrentHashMap.newKeySet();
175	
176	        ExecutorService pool = Executors.newFixedThreadPool(threads);
177	        for (int i = 0; i < threads; i++) {
178	            pool.submit(() -> {
179	                try {
180	                    gate.await();                          // all hit the lock at once
181	                    SeatHold h = tsvc.holdSeats("show-x", List.of("S1", "S2"));
182	                    wins.incrementAndGet();
183	                    winningHoldIds.add(h.holdId());
184	                } catch (SeatsUnavailableException expected) {
185	                    conflicts.incrementAndGet();           // typed loss
186	                } catch (Exception e) {
187	                    throw new RuntimeException(e);
188	                }
189	            });
190	        }
191	        pool.shutdown();
192	        assertTrue(pool.awaitTermination(15, TimeUnit.SECONDS), "all threads finished");
193	
194	        // Exactly one winner, all others lost with the TYPED exception (no surprises).
195	        assertEquals(1, wins.get(), "exactly one hold should win");
196	        assertEquals(1, winningHoldIds.size(), "winner has a unique hold id");
