9	// class allowed to change a seat's status. The booking service never writes
10	// `seat.status = BOOKED` directly — it calls hold(), confirm(), release(). That
11	// way illegal jumps (AVAILABLE straight to BOOKED, or BOOKED back to AVAILABLE)
12	// are impossible by construction.
13	// 🎙️ "ShowSeat is a tiny state machine. The service asks it to hold, confirm or
14	//      release — it never pokes the status field directly. So an illegal jump
15	//      like 'available straight to booked' simply cannot happen."
16	public class ShowSeat {
17	
18	    private final String seatLabel;        // e.g. "A1" — stable id within a showtime
19	    private SeatStatus status;
20	    @Nullable private String heldBy;       // hold id that owns this seat while HELD
21	    @Nullable private Instant heldUntil;   // when this hold expires (10 min after hold)
22	
23	    public ShowSeat(String seatLabel) {
24	        this.seatLabel = seatLabel;
25	        this.status = SeatStatus.AVAILABLE;
26	    }
27	
28	    public String getSeatLabel() {
29	        return seatLabel;
30	    }
31	
32	    public SeatStatus getStatus() {
33	        return status;
34	    }
35	
36	    @Nullable
37	    public String getHeldBy() {
38	        return heldBy;
39	    }
40	
41	    @Nullable
42	    public Instant getHeldUntil() {
43	        return heldUntil;
44	    }
45	
46	    // WHY: a seat can be grabbed only if it is AVAILABLE. A seat that is HELD or
47	    //      BOOKED is not free. This single check is what the two-phase commit
48	    //      relies on — the service checks isAvailable() on ALL seats first.
49	    public boolean isAvailable() {
50	        return status == SeatStatus.AVAILABLE;
51	    }
52	
53	    // WHY: move AVAILABLE -> HELD and stamp who holds it and until when.
54	    //      We assert the precondition so a caller that skipped the availability
55	    //      check cannot silently corrupt the state machine.
56	    public void hold(String holdId, Instant until) {
57	        if (status != SeatStatus.AVAILABLE) {
58	            throw new InvalidBookingException(
59	                "Cannot hold seat " + seatLabel + " in status " + status);
60	        }
61	        this.status = SeatStatus.HELD;
62	        this.heldBy = holdId;
63	        this.heldUntil = until;
64	    }
65	
66	    // WHY: move HELD -> BOOKED, but ONLY for the hold that actually owns the seat.
67	    //      If a different hold id tries to confirm, we reject — you cannot pay for
68	    //      a seat someone else is holding.
69	    // ⚠️ FOLLOW-UP: "What if the hold already expired when they pay?"
70	    //    → "The service checks expiry before calling confirm. If the sweeper
71	    //       already released it, the seat is AVAILABLE and this throws."
72	    public void confirm(String holdId) {
73	        if (status != SeatStatus.HELD || !holdId.equals(heldBy)) {
74	            throw new InvalidBookingException(
75	                "Cannot confirm seat " + seatLabel + " for hold " + holdId);
76	        }
77	        this.status = SeatStatus.BOOKED;
78	        this.heldBy = null;
79	        this.heldUntil = null;
80	    }
81	
82	    // WHY: send the seat back to AVAILABLE. This is "safe to call twice — second
83	    //      call does nothing" on purpose: the 10-minute sweeper and an explicit
84	    //      cancel can race, both deciding the hold is dead. Whichever runs first
85	    //      frees the seat; the second sees it is already AVAILABLE and returns.
86	    //      A BOOKED seat is final and is never released.
87	    // ⚠️ FOLLOW-UP: "What if release races with confirm?"
88	    //    → "Both run under the per-showtime lock, so they are ordered. If confirm
89	    //       wins, the seat is BOOKED and release leaves it alone."
90	    public void release() {
91	        if (status == SeatStatus.HELD) {
92	            this.status = SeatStatus.AVAILABLE;
93	            this.heldBy = null;
94	            this.heldUntil = null;
95	        }
96	    }
