// Probe: can the SAME seat end up confirmed/booked into TWO different tickets?
// Each thread holds 2 seats then confirms. Track which ticket booked which seat.
public class Stress2 {
    public static void main(String[] a) throws Exception {
        for (int round = 0; round < 300; round++) {
            MutableClock clock = new MutableClock(Instant.parse("2026-06-21T18:00:00Z"));
