            int threads = 24;
            CyclicBarrier gate = new CyclicBarrier(threads);
            ExecutorService pool = Executors.newFixedThreadPool(threads);
            // map seat -> ticketId that booked it; detect double booking
            ConcurrentHashMap<String,String> bookedBy = new ConcurrentHashMap<>();
            AtomicBoolean doubleBook = new AtomicBoolean(false);
            for (int i = 0; i < threads; i++) {
                final int idx = i;
                pool.submit(() -> {
                    try {
                        int base = idx % 3;
                        List<String> req = Arrays.asList("S"+base, "S"+(base+1));
                        gate.await();
                        SeatHold h = svc.holdSeats("show", req);
                        Ticket t = svc.confirmBooking(h.holdId());
                        for (String s : t.seatLabels()) {
                            String prev = bookedBy.putIfAbsent(s, t.ticketId());
                            if (prev != null) { doubleBook.set(true); }
                        }
                    } catch (BookingException ignored) {
                    } catch (Exception e) { throw new RuntimeException(e); }
                });
            }
            pool.shutdown();
            pool.awaitTermination(20, TimeUnit.SECONDS);
            if (doubleBook.get()) { System.out.println("DOUBLE BOOK round "+round); System.exit(1); }
        }
        System.out.println("Stress2 OK - no seat booked by two tickets across 300 rounds");
    }
}
